Author: YASDC, Inc.
Description: "USN: File Create"
EventId: 100
Channel: "FileSystem"
Provider: "USNJournalMonitor"
Maps:
  -
    Property: PayloadData1
    PropertyValue: "%targetfilename%"
    Values:
      -
        Name: targetfilename
        Value: "/Event/EventData/Data"
        Refine: "(?<=TargetFilename: ).+"
  -
    Property: PayloadData2
    PropertyValue: "%category%"
    Values:
      -
        Name: category
        Value: "/Event/EventData/Data"
        Refine: "(?<=Category: ).+"
  -
    Property: PayloadData3
    PropertyValue: "%utctime%"
    Values:
      -
        Name: utctime
        Value: "/Event/EventData/Data"
        Refine: "(?<=UtcTime: ).+"
  -
    Property: PayloadData4
    PropertyValue: "%reason%"
    Values:
      -
        Name: reason
        Value: "/Event/EventData/Data"
        Refine: "(?<=Reason: ).+"
  -
    Property: PayloadData5
    PropertyValue: "Usn: %usn% | JournalId: %journalid%"
    Values:
      -
        Name: usn
        Value: "/Event/EventData/Data"
        Refine: "(?<=Usn: )[0-9]+"
      -
        Name: journalid
        Value: "/Event/EventData/Data"
        Refine: "(?<=JournalId: )[0-9]+"
  -
    Property: PayloadData6
    PropertyValue: "IP: %sourceip% | VolSerial: %volserial% | Schema: %schema%"
    Values:
      -
        Name: sourceip
        Value: "/Event/EventData/Data"
        Refine: "(?<=SourceIP: ).+"
      -
        Name: volserial
        Value: "/Event/EventData/Data"
        Refine: "(?<=VolumeSerial: ).+"
      -
        Name: schema
        Value: "/Event/EventData/Data"
        Refine: "(?<=SchemaVersion: ).+"
